const fs=require("fs"),path=require("path"),flatted=require("flatted");function tryParse(e,r){let t;try{t=readJSON(e)}catch(e){t=r}return t}function readJSON(e){return flatted.parse(fs.readFileSync(e,{encoding:"utf8"}))}function writeJSON(e,r){fs.mkdirSync(path.dirname(e),{recursive:!0}),fs.writeFileSync(e,flatted.stringify(r))}module.exports={tryParse:tryParse,readJSON:readJSON,writeJSON:writeJSON};